{
    "Description": "Create a DynamoDB table using on demand billing.\n",
    "Resources": {
        "CustomerTable": {
            "Type": "AWS::DynamoDB::Table",
            "Metadata": {
                "Comment": "A simple table that passes security scanner checks",
                "checkov": {
                    "skip": [
                        {
                            "id": "CKV_AWS_119",
                            "comment": "SSEType KMS stores the key in the customer account"
                        }
                    ]
                },
                "guard": {
                    "SuppressedRules": [
                        "DYNAMODB_TABLE_ENCRYPTED_KMS"
                    ]
                }
            },
            "Properties": {
                "BillingMode": "PAY_PER_REQUEST",
                "AttributeDefinitions": [
                    {
                        "AttributeName": "pk",
                        "AttributeType": "S"
                    }
                ],
                "KeySchema": [
                    {
                        "AttributeName": "pk",
                        "KeyType": "HASH"
                    }
                ],
                "PointInTimeRecoverySpecification": {
                    "PointInTimeRecoveryEnabled": true
                },
                "SSESpecification": {
                    "SSEEnabled": true,
                    "SSEType": "KMS"
                }
            }
        }
    }
}

{
    "AWSTemplateFormatVersion": "2010-09-09",
    "Description": "This stack creates different EC2 Volumes\n",
    "Parameters": {
        "KmsKeyId": {
            "Description": "The KMS key master ID",
            "Type": "String"
        }
    },
    "Resources": {
        "Volume": {
            "DeletionPolicy": "Snapshot",
            "UpdateReplacePolicy": "Snapshot",
            "Type": "AWS::EC2::Volume",
            "Properties": {
                "AvailabilityZone": {
                    "Fn::Select": [
                        0,
                        {
                            "Fn::GetAZs": {
                                "Ref": "AWS::Region"
                            }
                        }
                    ]
                },
                "Encrypted": true,
                "KmsKeyId": {
                    "Ref": "KmsKeyId"
                },
                "Size": 10,
                "VolumeType": "gp2"
            }
        },
        "VolumeGp3": {
            "DeletionPolicy": "Snapshot",
            "UpdateReplacePolicy": "Snapshot",
            "Type": "AWS::EC2::Volume",
            "Properties": {
                "AvailabilityZone": {
                    "Fn::Select": [
                        0,
                        {
                            "Fn::GetAZs": {
                                "Ref": "AWS::Region"
                            }
                        }
                    ]
                },
                "Encrypted": true,
                "Iops": 3000,
                "KmsKeyId": {
                    "Ref": "KmsKeyId"
                },
                "Size": 10,
                "Throughput": 125,
                "VolumeType": "gp3"
            }
        },
        "VolumeIo2": {
            "DeletionPolicy": "Snapshot",
            "UpdateReplacePolicy": "Snapshot",
            "Type": "AWS::EC2::Volume",
            "Properties": {
                "AvailabilityZone": {
                    "Fn::Select": [
                        0,
                        {
                            "Fn::GetAZs": {
                                "Ref": "AWS::Region"
                            }
                        }
                    ]
                },
                "Encrypted": true,
                "KmsKeyId": {
                    "Ref": "KmsKeyId"
                },
                "Size": 10,
                "Iops": 100,
                "VolumeType": "io2"
            }
        }
    }
}

{
    "Description": "This stack creates SSM parameters of string\nand a list of strings\n",
    "Resources": {
        "ParameterString": {
            "Type": "AWS::SSM::Parameter",
            "Properties": {
                "Name": "Key",
                "Description": "SSM Parameter for storing a string",
                "Type": "String",
                "Value": "Value",
                "Tier": "Standard"
            }
        },
        "ParameterList": {
            "Type": "AWS::SSM::Parameter",
            "Properties": {
                "Name": "KeyList",
                "Description": "SSM Parameter for storing a list of strings",
                "Type": "StringList",
                "Value": "Value1,Value2",
                "Tier": "Standard"
            }
        }
    }
}

{   "Description": "This stack automates the creation of Bedrock Knowledge Base, Data Source, \nAgent, AgentAlias, Guardrail and GuardrailVersion. \n",
    "Parameters": {
        "OpenSearchCollectionARN": {
            "Description": "OpenSearch Service Serverless (AOSS) collection ARN.",
            "Type": "String"
        },
        "EmbeddingModelArn": {
            "Description": "Knowledge Base Model Arn, can use 'aws bedrock list-foundation-models' to get",
            "Type": "String"
        },
        "AOSSIndexName": {
            "Description": "Name of the vector index in the Amazon OpenSearch Service Serverless (AOSS) collection.",
            "Type": "String"
        },
        "VectorField": {
            "Description": "Provide a name for the field",
            "Type": "String"
        },
        "TextField": {
            "Description": "Provide additional information that a knowledge base can retrieve with vectors",
            "Type": "String"
        },
        "MetadataField": {
            "Description": "Provide additional metadata that a knowledge base can retrieve with vectors",
            "Type": "String"
        },
        "KnowledgeBaseName": {
            "Description": "The name of the knowledge base.",
            "Type": "String"
        },
        "BedrockExecutionRoleARNForKnowledgeBase": {
            "Description": "The knowledge base execution role-arn which is being trusted by your Opensearch serverless collection access-policy.",
            "Type": "String"
        },
        "KnowledgeBaseDescription": {
            "Description": "The description of the knowledge base.",
            "Type": "String"
        },
        "DataSourceName": {
            "Description": "Name of the Bedrock DataSource",
            "Type": "String"
        },
        "DataSourceBucketName": {
            "Description": "Name of the S3 bucket which stored the DataSource",
            "Type": "String"
        },
        "AgentName": {
            "Description": "Name of the Bedrock Agent",
            "Type": "String"
        },
        "FoundationModelForAgent": {
            "Description": "Foundation Model which will be used by your Bedrock Agent",
            "Type": "String"
        },
        "AgentInstruction": {
            "Description": "Instruction for your Bedrock Agent",
            "Type": "String"
        },
        "AgentDescription": {
            "Description": "Description for your Bedrock Agent",
            "Type": "String"
        },
        "AgentAliasName": {
            "Description": "The name of the alias of the agent",
            "Type": "String"
        },
        "AgentAliasDescription": {
            "Description": "The description of the alias of the agent",
            "Type": "String"
        },
        "GuardrailName": {
            "Description": "Name of the Bedrock Agent",
            "Type": "String"
        },
        "GuardrailVersionDescription": {
            "Description": "A description of the guardrail version",
            "Type": "String"
        }
    },
    "Resources": {
        "KnowledgeBaseWithAoss": {
            "Type": "AWS::Bedrock::KnowledgeBase",
            "Properties": {
                "Name": {
                    "Ref": "KnowledgeBaseName"
                },
                "Description": {
                    "Ref": "KnowledgeBaseDescription"
                },
                "RoleArn": {
                    "Ref": "BedrockExecutionRoleARNForKnowledgeBase"
                },
                "KnowledgeBaseConfiguration": {
                    "Type": "VECTOR",
                    "VectorKnowledgeBaseConfiguration": {
                        "EmbeddingModelArn": {
                            "Ref": "EmbeddingModelArn"
                        }
                    }
                },
                "StorageConfiguration": {
                    "Type": "OPENSEARCH_SERVERLESS",
                    "OpensearchServerlessConfiguration": {
                        "CollectionArn": {
                            "Ref": "OpenSearchCollectionARN"
                        },
                        "VectorIndexName": {
                            "Ref": "AOSSIndexName"
                        },
                        "FieldMapping": {
                            "VectorField": {
                                "Ref": "VectorField"
                            },
                            "TextField": {
                                "Ref": "TextField"
                            },
                            "MetadataField": {
                                "Ref": "MetadataField"
                            }
                        }
                    }
                }
            }
        },
        "DataSource": {
            "Type": "AWS::Bedrock::DataSource",
            "Properties": {
                "KnowledgeBaseId": {
                    "Ref": "KnowledgeBaseWithAoss"
                },
                "Name": {
                    "Ref": "DataSourceName"
                },
                "DataSourceConfiguration": {
                    "Type": "S3",
                    "S3Configuration": {
                        "BucketArn": {
                            "Fn::Sub": "arn:aws:s3:::${DataSourceBucketName}"
                        }
                    }
                },
                "DataDeletionPolicy": "DELETE"
            }
        },
        "AmazonBedrockExecutionRoleForAgentsQA": {
            "Type": "AWS::IAM::Role",
            "Properties": {
                "AssumeRolePolicyDocument": {
                    "Statement": [
                        {
                            "Effect": "Allow",
                            "Principal": {
                                "Service": "bedrock.amazonaws.com"
                            },
                            "Action": "sts:AssumeRole"
                        }
                    ]
                },
                "ManagedPolicyArns": [
                    "arn:aws:iam::aws:policy/AmazonBedrockFullAccess"
                ]
            }
        },
        "MyCustomKMSKey": {
            "Type": "AWS::KMS::Key",
            "Properties": {
                "Description": "Custom KMS Key for Bedrock Agent encryption",
                "EnableKeyRotation": true,
                "KeyPolicy": {
                    "Version": "2012-10-17",
                    "Statement": [
                        {
                            "Sid": "Allow Amazon Bedrock to encrypt and decrypt Agent resources on behalf of authorized users",
                            "Effect": "Allow",
                            "Principal": {
                                "Service": "bedrock.amazonaws.com"
                            },
                            "Action": [
                                "kms:*"
                            ],
                            "Resource": "*"
                        },
                        {
                            "Sid": "Allow account root to modify the KMS key",
                            "Effect": "Allow",
                            "Principal": {
                                "AWS": {
                                    "Fn::Sub": "arn:aws:iam::${AWS::AccountId}:root"
                                }
                            },
                            "Action": [
                                "kms:*"
                            ],
                            "Resource": "*"
                        }
                    ]
                }
            }
        },
        "Agent": {
            "Type": "AWS::Bedrock::Agent",
            "Properties": {
                "AgentName": {
                    "Ref": "AgentName"
                },
                "AgentResourceRoleArn": {
                    "Fn::GetAtt": [
                        "AmazonBedrockExecutionRoleForAgentsQA",
                        "Arn"
                    ]
                },
                "AutoPrepare": true,
                "FoundationModel": {
                    "Ref": "FoundationModelForAgent"
                },
                "Instruction": {
                    "Ref": "AgentInstruction"
                },
                "Description": {
                    "Ref": "AgentDescription"
                },
                "IdleSessionTTLInSeconds": 900,
                "CustomerEncryptionKeyArn": {
                    "Fn::GetAtt": [
                        "MyCustomKMSKey",
                        "Arn"
                    ]
                },
                "KnowledgeBases": [
                    {
                        "KnowledgeBaseId": {
                            "Ref": "KnowledgeBaseWithAoss"
                        },
                        "Description": {
                            "Ref": "KnowledgeBaseDescription"
                        },
                        "KnowledgeBaseState": "ENABLED"
                    }
                ]
            }
        },
        "AgentAliasResource": {
            "Type": "AWS::Bedrock::AgentAlias",
            "Properties": {
                "AgentId": {
                    "Ref": "Agent"
                },
                "AgentAliasName": {
                    "Ref": "AgentAliasName"
                },
                "Description": {
                    "Ref": "AgentAliasDescription"
                }
            }
        },
        "Guardrail": {
            "Type": "AWS::Bedrock::Guardrail",
            "DependsOn": [
                "KnowledgeBaseWithAoss"
            ],
            "Properties": {
                "BlockedInputMessaging": "Guardrail applied based on the input.",
                "BlockedOutputsMessaging": "Guardrail applied based on output.",
                "Name": {
                    "Ref": "GuardrailName"
                },
                "Description": "My Bedrock Guardrail created with AWS CFN",
                "ContentPolicyConfig": {
                    "FiltersConfig": [
                        {
                            "InputStrength": "HIGH",
                            "OutputStrength": "HIGH",
                            "Type": "SEXUAL"
                        },
                        {
                            "InputStrength": "HIGH",
                            "OutputStrength": "HIGH",
                            "Type": "VIOLENCE"
                        },
                        {
                            "InputStrength": "HIGH",
                            "OutputStrength": "HIGH",
                            "Type": "HATE"
                        },
                        {
                            "InputStrength": "HIGH",
                            "OutputStrength": "HIGH",
                            "Type": "INSULTS"
                        },
                        {
                            "InputStrength": "HIGH",
                            "OutputStrength": "HIGH",
                            "Type": "MISCONDUCT"
                        },
                        {
                            "InputStrength": "NONE",
                            "OutputStrength": "NONE",
                            "Type": "PROMPT_ATTACK"
                        }
                    ]
                },
                "SensitiveInformationPolicyConfig": {
                    "PiiEntitiesConfig": [
                        {
                            "Action": "BLOCK",
                            "Type": "EMAIL"
                        },
                        {
                            "Action": "ANONYMIZE",
                            "Type": "IP_ADDRESS"
                        }
                    ]
                },
                "TopicPolicyConfig": {
                    "TopicsConfig": [
                        {
                            "Definition": "Investment advice is inquiries, guidance, or recommendations about the management or allocation of funds or assets with the goal of generating returns or achieving specific financial objectives.",
                            "Examples": [
                                "Is investing in the stocks better than bonds?",
                                "Should I invest in gold?"
                            ],
                            "Name": "Investment Advice",
                            "Type": "DENY"
                        }
                    ]
                },
                "WordPolicyConfig": {
                    "ManagedWordListsConfig": [
                        {
                            "Type": "PROFANITY"
                        }
                    ],
                    "WordsConfig": [
                        {
                            "Text": "BLOCKTHISWORD"
                        }
                    ]
                },
                "ContextualGroundingPolicyConfig": {
                    "FiltersConfig": [
                        {
                            "Threshold": "0.8",
                            "Type": "GROUNDING"
                        },
                        {
                            "Threshold": "0.8",
                            "Type": "RELEVANCE"
                        }
                    ]
                }
            }
        },
        "GuardrailVersion": {
            "Type": "AWS::Bedrock::GuardrailVersion",
            "Properties": {
                "Description": {
                    "Ref": "GuardrailVersionDescription"
                },
                "GuardrailIdentifier": {
                    "Fn::GetAtt": [
                        "Guardrail",
                        "GuardrailArn"
                    ]
                }
            }
        }
    }
}

{
    "AWSTemplateFormatVersion": "2010-09-09",
    "Description": "This stack automates the creation of an AWS Auto Scaling group\nusing the latest EC2 AMI image using Amazon Linux 2. It also creates\nthe related resources like a launch template and security groups\n",
    "Parameters": {
        "LatestAmiId": {
            "Description": "Region specific image from the Parameter Store",
            "Type": "AWS::SSM::Parameter::Value<AWS::EC2::Image::Id>",
            "Default": "/aws/service/ami-amazon-linux-latest/amzn2-ami-hvm-x86_64-gp2"
        },
        "VpcId": {
            "Description": "A VPC ID for the security group",
            "Type": "AWS::EC2::VPC::Id"
        },
        "Subnets": {
            "Description": "A list of subnets for the Auto Scaling group",
            "Type": "List<AWS::EC2::Subnet::Id>"
        }
    },
    "Resources": {
        "SecurityGroup": {
            "Type": "AWS::EC2::SecurityGroup",
            "Properties": {
                "GroupDescription": "Auto scaling group security group",
                "VpcId": {
                    "Ref": "VpcId"
                }
            }
        },
        "LaunchTemplate": {
            "Type": "AWS::EC2::LaunchTemplate",
            "Properties": {
                "LaunchTemplateName": {
                    "Fn::Sub": "${AWS::StackName}-launch-template"
                },
                "LaunchTemplateData": {
                    "ImageId": {
                        "Ref": "LatestAmiId"
                    },
                    "InstanceType": "t3.micro",
                    "SecurityGroupIds": [
                        {
                            "Fn::GetAtt": [
                                "SecurityGroup",
                                "GroupId"
                            ]
                        }
                    ],
                    "MetadataOptions": {
                        "HttpEndpoint": "disabled"
                    }
                }
            }
        },
        "AutoScalingGroup": {
            "Type": "AWS::AutoScaling::AutoScalingGroup",
            "Properties": {
                "LaunchTemplate": {
                    "LaunchTemplateId": {
                        "Ref": "LaunchTemplate"
                    },
                    "Version": {
                        "Fn::GetAtt": [
                            "LaunchTemplate",
                            "LatestVersionNumber"
                        ]
                    }
                },
                "MaxSize": "1",
                "MinSize": "0",
                "DesiredCapacity": "1",
                "VPCZoneIdentifier": {
                    "Ref": "Subnets"
                }
            }
        }
    }
}

{
    "AWSTemplateFormatVersion": "2010-09-09",
    "Description": "CodePipeline for continuous integration build and continuous deployment",
    "Parameters": {
        "CodeBuildStack": {
            "Description": "Name of the code build stack which should have been deployed before this stack",
            "Type": "String"
        }
    },
    "Resources": {
        "PipelineRole": {
            "Type": "AWS::IAM::Role",
            "Properties": {
                "AssumeRolePolicyDocument": {
                    "Version": "2012-10-17",
                    "Statement": [
                        {
                            "Effect": "Allow",
                            "Principal": {
                                "Service": [
                                    "codepipeline.amazonaws.com"
                                ]
                            },
                            "Action": [
                                "sts:AssumeRole"
                            ]
                        }
                    ]
                },
                "Policies": [
                    {
                        "PolicyName": "CanAccessCodeCommit",
                        "PolicyDocument": {
                            "Version": "2012-10-17",
                            "Statement": [
                                {
                                    "Effect": "Allow",
                                    "Action": [
                                        "codecommit:GetBranch",
                                        "codecommit:GetCommit",
                                        "codecommit:UploadArchive",
                                        "codecommit:GetUploadArchiveStatus"
                                    ],
                                    "Resource": [
                                        {
                                            "Fn::ImportValue": {
                                                "Fn::Sub": "${CodeBuildStack}-CodeCommitArn"
                                            }
                                        }
                                    ]
                                }
                            ]
                        }
                    },
                    {
                        "PolicyName": "CanAccessS3",
                        "PolicyDocument": {
                            "Version": "2012-10-17",
                            "Statement": [
                                {
                                    "Effect": "Allow",
                                    "Action": "s3:ListBucket",
                                    "Resource": "*"
                                },
                                {
                                    "Effect": "Allow",
                                    "Action": [
                                        "s3:GetObject",
                                        "s3:GetObjectVersion",
                                        "s3:GetBucketVersioning",
                                        "s3:PutObject",
                                        "s3:GetBucketPolicy",
                                        "s3:GetObjectAcl",
                                        "s3:PutObjectAcl",
                                        "s3:DeleteObject"
                                    ],
                                    "Resource": [
                                        {
                                            "Fn::ImportValue": {
                                                "Fn::Sub": "${CodeBuildStack}-PipelineS3BucketArn"
                                            }
                                        },
                                        {
                                            "Fn::Sub": [
                                                "${filename}/*",
                                                {
                                                    "filename": {
                                                        "Fn::ImportValue": {
                                                            "Fn::Sub": "${CodeBuildStack}-PipelineS3BucketArn"
                                                        }
                                                    }
                                                }
                                            ]
                                        }
                                    ]
                                }
                            ]
                        }
                    },
                    {
                        "PolicyName": "CanStartCodeBuild",
                        "PolicyDocument": {
                            "Version": "2012-10-17",
                            "Statement": [
                                {
                                    "Effect": "Allow",
                                    "Action": [
                                        "codebuild:BatchGetBuilds",
                                        "codebuild:StartBuild"
                                    ],
                                    "Resource": [
                                        {
                                            "Fn::ImportValue": {
                                                "Fn::Sub": "${CodeBuildStack}-AppBuildArn"
                                            }
                                        },
                                        {
                                            "Fn::ImportValue": {
                                                "Fn::Sub": "${CodeBuildStack}-AppDeployArn"
                                            }
                                        }
                                    ]
                                }
                            ]
                        }
                    }
                ]
            }
        },
        "EventRole": {
            "Type": "AWS::IAM::Role",
            "Properties": {
                "AssumeRolePolicyDocument": {
                    "Version": "2012-10-17",
                    "Statement": [
                        {
                            "Effect": "Allow",
                            "Principal": {
                                "Service": [
                                    "events.amazonaws.com"
                                ]
                            },
                            "Action": "sts:AssumeRole"
                        }
                    ]
                },
                "Path": "/",
                "Policies": [
                    {
                        "PolicyName": "eb-pipeline-execution",
                        "PolicyDocument": {
                            "Version": "2012-10-17",
                            "Statement": [
                                {
                                    "Effect": "Allow",
                                    "Action": "codepipeline:StartPipelineExecution",
                                    "Resource": {
                                        "Fn::Join": [
                                            "",
                                            [
                                                "arn:aws:codepipeline:",
                                                {
                                                    "Ref": "AWS::Region"
                                                },
                                                ":",
                                                {
                                                    "Ref": "AWS::AccountId"
                                                },
                                                ":",
                                                {
                                                    "Ref": "Pipeline"
                                                }
                                            ]
                                        ]
                                    }
                                }
                            ]
                        }
                    }
                ]
            }
        },
        "EventRule": {
            "Type": "AWS::Events::Rule",
            "Properties": {
                "EventPattern": {
                    "source": [
                        "aws.codecommit"
                    ],
                    "detail-type": [
                        "CodeCommit Repository State Change"
                    ],
                    "resources": [
                        {
                            "Fn::ImportValue": {
                                "Fn::Sub": "${CodeBuildStack}-CodeCommitArn"
                            }
                        }
                    ],
                    "detail": {
                        "event": [
                            "referenceCreated",
                            "referenceUpdated"
                        ],
                        "referenceType": [
                            "branch"
                        ],
                        "referenceName": [
                            "main"
                        ]
                    }
                },
                "Targets": [
                    {
                        "Arn": {
                            "Fn::Join": [
                                "",
                                [
                                    "arn:aws:codepipeline:",
                                    {
                                        "Ref": "AWS::Region"
                                    },
                                    ":",
                                    {
                                        "Ref": "AWS::AccountId"
                                    },
                                    ":",
                                    {
                                        "Ref": "Pipeline"
                                    }
                                ]
                            ]
                        },
                        "RoleArn": {
                            "Fn::GetAtt": [
                                "EventRole",
                                "Arn"
                            ]
                        },
                        "Id": "codepipeline-Pipeline"
                    }
                ]
            }
        },
        "Pipeline": {
            "Type": "AWS::CodePipeline::Pipeline",
            "Properties": {
                "Name": {
                    "Fn::Sub": "${AWS::StackName}-Code-Pipeline"
                },
                "ArtifactStore": {
                    "Type": "S3",
                    "Location": {
                        "Fn::ImportValue": {
                            "Fn::Sub": "${CodeBuildStack}-PipelineS3Bucket"
                        }
                    }
                },
                "RestartExecutionOnUpdate": false,
                "RoleArn": {
                    "Fn::GetAtt": [
                        "PipelineRole",
                        "Arn"
                    ]
                },
                "Stages": [
                    {
                        "Name": "Source",
                        "Actions": [
                            {
                                "Name": "Source",
                                "ActionTypeId": {
                                    "Category": "Source",
                                    "Owner": "AWS",
                                    "Provider": "CodeCommit",
                                    "Version": 1
                                },
                                "Configuration": {
                                    "RepositoryName": {
                                        "Fn::ImportValue": {
                                            "Fn::Sub": "${CodeBuildStack}-CodeCommitName"
                                        }
                                    },
                                    "BranchName": "main",
                                    "PollForSourceChanges": false
                                },
                                "OutputArtifacts": [
                                    {
                                        "Name": "Source"
                                    }
                                ]
                            }
                        ]
                    },
                    {
                        "Name": "Build-AppBuild",
                        "Actions": [
                            {
                                "Name": "App-Build",
                                "ActionTypeId": {
                                    "Category": "Build",
                                    "Owner": "AWS",
                                    "Provider": "CodeBuild",
                                    "Version": 1
                                },
                                "Configuration": {
                                    "ProjectName": {
                                        "Fn::ImportValue": {
                                            "Fn::Sub": "${CodeBuildStack}-AppBuild"
                                        }
                                    }
                                },
                                "InputArtifacts": [
                                    {
                                        "Name": "Source"
                                    }
                                ],
                                "OutputArtifacts": [
                                    {
                                        "Name": "FullZip"
                                    }
                                ],
                                "RunOrder": 1
                            }
                        ]
                    },
                    {
                        "Name": "Deploy-App",
                        "Actions": [
                            {
                                "Name": "Approval",
                                "ActionTypeId": {
                                    "Category": "Approval",
                                    "Owner": "AWS",
                                    "Provider": "Manual",
                                    "Version": 1
                                },
                                "Configuration": {
                                    "CustomData": "Review the build output and approve to deploy"
                                },
                                "RunOrder": 2
                            },
                            {
                                "Name": "App-Deploy",
                                "ActionTypeId": {
                                    "Category": "Build",
                                    "Owner": "AWS",
                                    "Provider": "CodeBuild",
                                    "Version": 1
                                },
                                "Configuration": {
                                    "ProjectName": {
                                        "Fn::ImportValue": {
                                            "Fn::Sub": "${CodeBuildStack}-AppDeploy"
                                        }
                                    },
                                    "PrimarySource": "Source",
                                    "EnvironmentVariables": "[{\"name\":\"ENVIRONMENT\",\"value\":\"SampleEnv\",\"type\":\"PLAINTEXT\"}]"
                                },
                                "InputArtifacts": [
                                    {
