{
  "AWSTemplateFormatVersion": "2010-09-09",
  "Conditions": {
    "DoBucketStuff": {
      "Fn::Not": [ { "Fn::Equals": [ { "Ref": "BackupBucketName" }, "" ] } ]
    },
    "EnableCwaFetch": {
      "Fn::Not": [ { "Fn::Equals": [ { "Ref": "CloudwatchBucketName" }, "" ] } ]
    },
    "PrettyRole": {
      "Fn::Not": [ { "Fn::Equals": [ { "Ref": "RolePrefix" }, "" ] } ]
    }
  },
  "Description": "Template to set up IAM role needed by Gluster instances.",
  "Metadata": {
    "AWS::CloudFormation::Interface": {
      "ParameterGroups": [
        {
          "Label": {
            "default": ""
          },
          "Parameters": [
            "RolePrefix",
            "BackupBucketName",
            "CloudwatchBucketName"
          ]
        }
      ]
    }
  },
  "Outputs": {
    "InstanceRoleArn": {
      "Description": "ARN of the instance role",
      "Export": { "Name": { "Fn::Sub": "${AWS::StackName}-InstanceRoleArn" } },
      "Value": { "Fn::GetAtt": [ "InstanceRole", "Arn" ] }
    },
    "InstanceRoleName": {
      "Description": "Name of the instance role",
      "Export": { "Name": { "Fn::Sub": "${AWS::StackName}-InstanceRoleName" } },
      "Value": { "Ref": "InstanceRole" }
    },
    "InstanceRoleProfile": {
      "Description": "Profile of the instance role",
      "Export": { "Name": { "Fn::Sub": "${AWS::StackName}-InstanceRoleProfile" } },
      "Value": { "Ref": "InstanceProfile" }
    }
  },
  "Parameters": {
    "BackupBucketName": {
      "Description": "Name of S3 Bucket used to host Gluster backups",
      "Type": "String"
    },
    "CloudwatchBucketName": {
      "Description": "Name of the S3 Bucket hosting the CloudWatch agent archive files",
      "Type": "String"
    },
    "RolePrefix": {
      "Description": "Prefix to apply to IAM role to make things a bit prettier (optional).",
      "Type": "String"
    }
  },
  "Resources": {
    "InstancePolicy": {
      "Properties": {
        "Description": "Policy to provide instance-level access to needed AWS-level resources",
        "Path": "/",
        "PolicyDocument": {
          "Statement": [
            {
              "Fn::If": [
                "DoBucketStuff",
                {
                  "Action": [
                    "s3:*"
                  ],
                  "Effect": "Allow",
                  "Resource": [
                    {
                      "Fn::Join": [
                        "",
                        [
                          "arn:",
                          { "Ref": "AWS::Partition" },
                          ":s3:::",
                          { "Ref": "BackupBucketName" },
                          ""
                        ]
                      ]
                    },
                    {
                      "Fn::Join": [
                        "",
                        [
                          "arn:",
                          { "Ref": "AWS::Partition" },
                          ":s3:::",
                          { "Ref": "BackupBucketName" },
                          "/*"
                        ]
                      ]
                    }
                  ],
                  "Sid": "BackupsEnablement"
                },
                { "Ref": "AWS::NoValue" }
              ]
            },
            {
              "Fn::If": [
                "EnableCwaFetch",
                {
                  "Action": [
                    "s3:GetObject",
                    "s3:ListBucket"
                  ],
                  "Effect": "Allow",
                  "Resource": [
                    {
                      "Fn::Join": [
                        "",
                        [
                          "arn:",
                          { "Ref": "AWS::Partition" },
                          ":s3:::",
                          { "Ref": "CloudwatchBucketName" },
                          "/*"
                        ]
                      ]
                    }
                  ],
                  "Sid": "CwaFetch"
                },
                { "Ref": "AWS::NoValue" }
              ]
            },
            {
              "Action": [
                "cloudformation:DescribeStackResource",
                "cloudformation:SignalResource",
                "ec2:DescribeInstances"
              ],
              "Effect": "Allow",
              "Resource": [
                "*"
              ],
              "Sid": "ASGsupport"
            },
            {
              "Fn::If": [
                "EnableCwaFetch",
                {
                  "Action": [
                    "logs:PutLogEvents",
                    "logs:CreateLogStream"
                  ],
                  "Effect": "Allow",
                  "Resource": [
                    "*"
                  ],
                  "Sid": "CwaLogAllow"
                },
                { "Ref": "AWS::NoValue" }
              ]
            }
          ],
          "Version": "2012-10-17"
        },
        "Roles": [ { "Ref": "InstanceRole" } ]
      },
      "Type": "AWS::IAM::ManagedPolicy"
    },
    "InstanceProfile": {
      "Properties": {
        "Path": "/",
        "Roles": [ { "Ref": "InstanceRole" } ]
      },
      "Type": "AWS::IAM::InstanceProfile"
    },
    "InstanceRole": {
      "Properties": {
        "AssumeRolePolicyDocument": {
          "Statement": [
            {
              "Action": "sts:AssumeRole",
              "Effect": "Allow",
              "Principal": {
                "Service": {
                  "Fn::Join": [
                    ".",
                    [
                      "ec2",
                      { "Ref": "AWS::URLSuffix" }
                    ]
                  ]
                }
              }
            }
          ],
          "Version": "2012-10-17"
        },
        "Path": "/",
        "RoleName": {
          "Fn::If": [
            "PrettyRole",
            {
              "Fn::Join": [
                "-",
                [
                  { "Ref": "RolePrefix" },
                  { "Ref": "AWS::StackName" }
                ]
              ]
            },
            { "Ref": "AWS::NoValue" }
          ]
        }
      },
      "Type": "AWS::IAM::Role"
    }
  }
}

