              "Resource": [
                "*"
              ],
              "Condition" : {
                "Null": {"aws:MultiFactorAuthAge":"3600"},
                "Bool": {"aws:SecureTransport":"true"}
              }
            },
            {
              "Sid": "ViewAllReadOnlyIamInfo",
              "Effect": "Allow",
              "Action": [
                "iam:Get*",
                "iam:List*"
              ],
              "Resource": [
                "*"
              ],
              "Condition" : {
                "Null": {"aws:MultiFactorAuthAge":"3600"},
                "Bool": {"aws:SecureTransport":"true"}
              }
            },
            {
              "Sid": "ManageSupport",
              "Effect": "Allow",
