{
  "AWSTemplateFormatVersion": "2010-09-09",
  "Description": "v1.0 Creates Instance Profile for Web Applications",
  "Parameters": {
    "Environment": {
      "Description": "Name of the environment this VPC represents",
      "Type": "String",
      "MinLength": "4",
      "MaxLength": "14",
      "AllowedPattern": "[a-z0-9]*",
      "ConstraintDescription": "can contain only lower case alphanumeric characters."
    },
    "ApplicationName": {
      "Type": "String"
    }
  },
  "Outputs": {
    "InstanceProfile": {
      "Value": {
        "Ref": "InstanceProfile"
      }
    }
  },
  "Resources": {
    "Role": {
      "Type": "AWS::IAM::Role",
      "Properties": {
        "AssumeRolePolicyDocument": {
          "Statement": [
            {
              "Effect": "Allow",
              "Principal": {
                "Service": [
                  "ec2.amazonaws.com"
                ]
              },
              "Action": [
                "sts:AssumeRole"
              ]
            }
          ]
        },
        "Path": "/",
        "Policies": [
          {
            "PolicyName": "DescribeInstances",
            "PolicyDocument": {
              "Statement": [
                {
                  "Effect": "Allow",
                  "Action": [
                    "ec2:DescribeInstances"
                  ],
                  "Resource": "*"
                }
              ]
            }
          },
          {
            "PolicyName": "S3BucketAccess",
            "PolicyDocument": {
              "Statement": [
                {
                  "Effect": "Allow",
                  "Action": [
                    "s3:*"
                  ],
                  "Resource": [
                    {
                      "Fn::Join": [
                        ":",
                        [
                          "arn:aws:s3::",
                          {
                            "Fn::Join": [
                              "-",
                              [
                                {
                                  "Ref": "Environment"
                                },
                                {
                                  "Ref": "ApplicationName"
                                },
                                "private"
                              ]
                            ]
                          }
                        ]
                      ]
                    },
                    {
                      "Fn::Join": [
                        ":",
                        [
                          "arn:aws:s3::",
                          {
                            "Fn::Join": [
                              "-",
                              [
                                {
                                  "Ref": "Environment"
                                },
                                {
                                  "Ref": "ApplicationName"
                                },
                                "private/*"
                              ]
                            ]
                          }
                        ]
                      ]
                    },
                    {
                      "Fn::Join": [
                        ":",
                        [
                          "arn:aws:s3::",
                          {
                            "Fn::Join": [
                              "-",
                              [
                                {
                                  "Ref": "Environment"
                                },
                                {
                                  "Ref": "ApplicationName"
                                },
                                "public"
                              ]
                            ]
                          }
                        ]
                      ]
                    },
                    {
                      "Fn::Join": [
                        ":",
                        [
                          "arn:aws:s3::",
                          {
                            "Fn::Join": [
                              "-",
                              [
                                {
                                  "Ref": "Environment"
                                },
                                {
                                  "Ref": "ApplicationName"
                                },
                                "pubic/*"
                              ]
                            ]
                          }
                        ]
                      ]
                    }
                  ]
                }
              ]
            }
          }
        ]
      }
    },
    "InstanceProfile": {
      "Type": "AWS::IAM::InstanceProfile",
      "Properties": {
        "Path": "/",
        "Roles": [
          {
            "Ref": "Role"
          }
        ]
      }
    }
  }
}

