{
  "AWSTemplateFormatVersion": "2010-09-09",

  "Description": "AGILEFANT IAM 1.0.0 - Author Chris Morann",

  "Parameters": {
    "CfnBucketName": {
      "Type": "String",
      "Default": "agilefant"
    }
  },

  "Resources": {
    "InstanceRole":{
      "Type":"AWS::IAM::Role",
      "Properties":{
        "AssumeRolePolicyDocument":{
          "Statement":[
          {
            "Effect":"Allow",
            "Principal":{
              "Service":[
              "ec2.amazonaws.com"
              ]
            },
            "Action":[
              "sts:AssumeRole"
            ]
          }
          ]
        },
        "Path":"/"
      }
    },

    "RolePolicies":{
        "Type":"AWS::IAM::Policy",
        "Properties":{
          "PolicyName":"S3Download",
          "PolicyDocument":{
            "Statement":[
            {
              "Action":[
                "s3:ListBucket",
                "s3:GetBucketLocation",
                "s3:GetObject"
              ],
              "Effect":"Allow",
              "Resource": [
              {
                "Fn::Join": [ "", [
                "arn:aws:s3:::",
                "cfnstore"
                ] ]
            },

            {
              "Fn::Join": [ "", [
                "arn:aws:s3:::",
                "cfnstore/",
                { "Ref": "CfnBucketName"},
                "/*"
              ] ]
            }

          ]
            }
            ]
        },
        "Roles":[
          { "Ref":"InstanceRole" }
        ]
         }
      },

    "BucketProfile" : {
      "Type": "AWS::IAM::InstanceProfile",
        "Properties": {
          "Path": "/",
          "Roles": [
            { "Ref":  "InstanceRole"}
            ]
          }
      }
  },

  "Outputs": {
    "BucketProfile": {
      "Value": { "Ref": "BucketProfile"}
    },

    "InstanceRole": {
      "Value": { "Ref": "InstanceRole"}
    }
  }
}

{
  "AWSTemplateFormatVersion": "2010-09-09",
  "Description": "This template sets up the IAM role needed by an Artifactory instance",
  "Parameters": {
    "ArtifactBucket": {
      "Description": "S3 Bucket to host Artifactory Artifacts",
      "Type": "String",
      "AllowedPattern": "^[a-zA-Z][a-zA-Z0-9-]*[a-zA-Z0-9]*$"
    }
  },
  "Resources": {
    "InstancePolicy" : {
      "Type": "AWS::IAM::ManagedPolicy",
      "Properties": {
        "Description" : "Policy to provide instance-level access to needed AWS-level resources",
        "Path" : "/",
        "PolicyDocument": {
          "Version" : "2012-10-17",
          "Statement": [
            {
              "Effect": "Allow",
              "Action": [
                "s3:*"
              ],
              "Resource": [
                { "Fn::Join" : [ "", [
                  "arn:aws:s3:::",
                    { "Ref" : "ArtifactBucket" },
                    ""
                ]]},
                { "Fn::Join" : [ "", [
                  "arn:aws:s3:::",
                    { "Ref" : "ArtifactBucket" },
                    "/*"
                ]]}
              ]
            },
            {
              "Effect": "Allow",
              "Action": [
                "cloudformation:DescribeStackResource"
              ],
              "Resource": [
                "*"
              ]
            }
          ]
        },
        "Roles": [{ "Ref" : "InstanceRole" }]
      }
    },
    "InstanceRole": {
      "Type": "AWS::IAM::Role",
      "Properties": {
        "AssumeRolePolicyDocument": {
          "Version": "2012-10-17",
          "Statement": [{
            "Action": "sts:AssumeRole",
            "Effect": "Allow",
            "Principal": {
              "Service": "ec2.amazonaws.com"
            }
          }]
        },
        "Path": "/"
      }
    },
    "InstanceProfile": {
      "Type": "AWS::IAM::InstanceProfile",
      "Properties": {
        "Path": "/",
        "Roles": [ { "Ref" : "InstanceRole" } ]
      }
    }
  },
  "Outputs": {
    "InstanceRole": {
      "Value": { "Ref" : "InstanceRole" },
      "Description" : "Name of the instance role"
    },
    "InstanceRoleProfile" : {
      "Value":  { "Ref" : "InstanceProfile" },
      "Description" : "Profile of the instance role"
    },
    "InstanceRoleArn" : {
      "Value": { "Fn::GetAtt" : [ "InstanceRole", "Arn" ] },
      "Description" : "ARN of the instance role"
    }
  }
}

