{
  "AWSTemplateFormatVersion": "2010-09-09",
  "Description": "hello YOGA DNS records and Amplify configuration",
  "Parameters": {
    "GitHubPersonalAccessToken": {
      "Type": "String",
      "Description": "A GitHub Personal access token is required, even for public repos."
    }
  },
  "Resources": {
    "HostedZone": {
      "Type": "AWS::Route53::HostedZone",
      "Properties": {
        "HostedZoneConfig": {
          "Comment": {
            "Fn::Sub": [
              "Managed by ${StackName} stack.",
              { "StackName": { "Ref": "AWS::StackName" } }
            ]
          }
        },
        "Name": "hello-yoga.co.uk"
      }
    },
    "EmailDnsRecords": {
      "Type": "AWS::Route53::RecordSetGroup",
      "Properties": {
        "Comment": "DNS records for iCloud Mail",
        "HostedZoneId": { "Ref": "HostedZone" },
        "RecordSets": [
          {
            "Name": "hello-yoga.co.uk",
            "ResourceRecords": [
              "\"v=spf1 redirect=icloud.com\"",
              "\"apple-domain=YJSfSmnGhO5EbjA5\""
            ],
            "TTL": 3600,
            "Type": "TXT"
          },
          {
            "Name": "hello-yoga.co.uk",
            "ResourceRecords": [
              "10 mx01.mail.icloud.com.",
              "10 mx02.mail.icloud.com."
            ],
            "TTL": 3600,
            "Type": "MX"
          },
          {
            "Name": "sig1._domainkey.hello-yoga.co.uk",
            "ResourceRecords": [
              "sig1.dkim.hello-yoga.co.uk.at.icloudmailadmin.com."
            ],
            "TTL": 3600,
            "Type": "CNAME"
          }
        ]
      }
    },
    "AmplifyApp": {
      "Type": "AWS::Amplify::App",
      "Properties": {
        "AccessToken": { "Ref": "GitHubPersonalAccessToken" },
        "AutoBranchCreationConfig": {
          "EnableAutoBranchCreation": true,
          "EnableAutoBuild": true,
          "Stage": "DEVELOPMENT"
        },
        "EnableBranchAutoDeletion": true,
        "IAMServiceRole": {
          "Fn::GetAtt": ["AmplifyConsoleServiceRole", "Arn"]
        },
        "Name": "hello YOGA",
        "Repository": "https://github.com/michrome/hello-yoga"
      }
    },
    "AmplifyBranch": {
      "Type": "AWS::Amplify::Branch",
      "Properties": {
        "AppId": { "Fn::GetAtt": ["AmplifyApp", "AppId"] },
        "BranchName": "main",
        "Stage": "PRODUCTION"
      }
    },
    "AmplifyDomain": {
      "Type": "AWS::Amplify::Domain",
      "Properties": {
        "AppId": { "Fn::GetAtt": ["AmplifyApp", "AppId"] },
        "DomainName": "hello-yoga.co.uk",
        "EnableAutoSubDomain": true,
        "SubDomainSettings": [
          {
            "BranchName": "main",
            "Prefix": ""
          },
          {
            "BranchName": "main",
            "Prefix": "www"
          }
        ]
      }
    },
    "AmplifyConsoleServiceRole": {
      "Type": "AWS::IAM::Role",
      "Properties": {
        "AssumeRolePolicyDocument": {
          "Version": "2012-10-17",
          "Statement": [
            {
              "Effect": "Allow",
              "Principal": {
                "Service": ["amplify.amazonaws.com"]
              },
              "Action": "sts:AssumeRole"
            }
          ]
        },
        "Description": "Amplify Console Service Role for hello YOGA",
        "ManagedPolicyArns": [
          "arn:aws:iam::aws:policy/AdministratorAccess-Amplify"
        ]
      }
    }
  }
}

{
   "AWSTemplateFormatVersion":"2010-09-09",
   "Parameters":{
      "NameTag":{
         "Description":"The Name Tag used for the resources to be created.",
         "Type":"String",
         "Default":"JIRAH"
      },
      "Environment":{
         "Description":"The Environment Type",
         "Type":"String",
         "Default":"DEV"
      },
      "WEBDesiredCount":{
         "Type":"Number",
         "Default":2
      },
      "APIDesiredCount":{
         "Type":"Number",
         "Default":2
      },
      "WEBCluster":{
         "Type":"String"
      },
      "APICluster":{
         "Type":"String"
      },
      "WEBTaskDefinition":{
         "Type":"String"
      },
      "APITaskDefinition":{
         "Type":"String"
      },
      "WEBSecurityGroup":{
         "Type":"String"
      },
      "APISecurityGroup":{
         "Type":"String"
      },
      "WEBSubnet1":{
         "Type":"String"
      },
      "WEBSubnet2":{
         "Type":"String"
      },
      "APISubnet1":{
         "Type":"String"
      },
      "APISubnet2":{
         "Type":"String"
      },
      "WEBPublicAlbTargetGroupArn":{
         "Type":"String"
      },
      "APIPublicAlbTargetGroupArn":{
         "Type":"String"
      }
   },
   "Resources":{
      "TaskExecutionRole":{
         "Type":"AWS::IAM::Role",
         "Properties":{
            "Path":"/",
            "AssumeRolePolicyDocument":{
               "Version":"2012-10-17",
               "Statement":[
                  {
                     "Action":"sts:AssumeRole",
                     "Effect":"Allow",
                     "Principal":{
                        "Service":"ecs-tasks.amazonaws.com"
                     }
                  }
               ]
            },
            "ManagedPolicyArns":[
               "arn:aws:iam::aws:policy/service-role/AmazonECSTaskExecutionRolePolicy"
            ]
         }
      },
      "WEBFargateService":{
         "Type":"AWS::ECS::Service",
         "Properties":{
            "Cluster":{
               "Ref":"WEBCluster"
            },
            "DesiredCount":{
               "Ref":"WEBDesiredCount"
            },
            "TaskDefinition":{
               "Ref":"WEBTaskDefinition"
            },
            "ServiceName":{
               "Fn::Sub":"${NameTag}-${Environment}-WEB-SERVICE"
            },
            "LaunchType":"FARGATE",
            "NetworkConfiguration":{
               "AwsvpcConfiguration":{
                  "AssignPublicIp":"ENABLED",
                  "SecurityGroups":[
                     {
                        "Ref":"WEBSecurityGroup"
                     }
                  ],
                  "Subnets":[
                     {
                        "Ref":"WEBSubnet1"
                     },
                     {
                        "Ref":"WEBSubnet2"
                     }
                  ]
               }
            },
            "LoadBalancers":[
               {
                  "ContainerName":{
                     "Fn::Sub":"${NameTag}-${Environment}-WEB-Container"
                  },
                  "ContainerPort":"3000",
                  "TargetGroupArn":{
                     "Ref":"WEBPublicAlbTargetGroupArn"
                  }
               }
            ],
            "Tags":[
               {
                  "Key":"Name",
                  "Value":{
                     "Fn::Sub":"${NameTag}-${Environment}-WEB-SERVICE"
                  }
               }
            ]
         }
      },
      "APIFargateService":{
         "Type":"AWS::ECS::Service",
         "Properties":{
            "Cluster":{
               "Ref":"APICluster"
            },
            "DesiredCount":{
               "Ref":"APIDesiredCount"
            },
            "TaskDefinition":{
               "Ref":"APITaskDefinition"
            },
            "ServiceName":{
               "Fn::Sub":"${NameTag}-${Environment}-API-SERVICE"
            },
            "LaunchType":"FARGATE",
            "NetworkConfiguration":{
               "AwsvpcConfiguration":{
                  "AssignPublicIp":"ENABLED",
                  "SecurityGroups":[
                     {
                        "Ref":"APISecurityGroup"
                     }
                  ],
                  "Subnets":[
                     {
                        "Ref":"APISubnet1"
                     },
                     {
                        "Ref":"APISubnet2"
                     }
                  ]
               }
            },
            "LoadBalancers":[
               {
                  "ContainerName":{
                     "Fn::Sub":"${NameTag}-${Environment}-API-Container"
                  },
                  "ContainerPort":"9990",
                  "TargetGroupArn":{
                     "Ref":"APIPublicAlbTargetGroupArn"
                  }
               }
            ],
            "Tags":[
               {
                  "Key":"Name",
                  "Value":{
                     "Fn::Sub":"${NameTag}-${Environment}-API-SERVICE"
                  }
               }
            ]
         }
      }
   },
   "Outputs":{
      "WEBService":{
         "Value":{
            "Ref":"WEBFargateService"
         }
      },
      "APIService":{
         "Value":{
            "Ref":"APIFargateService"
         }
      }
   }
}
